<template>
  <div class="recommend-page">
    <h2>智能推荐</h2>

    <!-- 输入摘要 -->
    <el-card class="summary-card" shadow="never">
      <el-descriptions :column="4" border>
        <el-descriptions-item label="省份">{{ user.province }}</el-descriptions-item>
        <el-descriptions-item label="科类">{{ user.categoryLabel }}</el-descriptions-item>
        <el-descriptions-item label="分数">{{ user.score }} 分</el-descriptions-item>
        <el-descriptions-item label="位次">{{ user.position.toLocaleString() }}</el-descriptions-item>
      </el-descriptions>
    </el-card>

    <!-- 筛选区 -->
    <el-card class="filter-card" shadow="never">
      <template #header>
        <span>筛选条件</span>
      </template>
      <el-form :inline="true" class="filter-form">
        <el-form-item label="城市">
          <el-select v-model="filters.cities" multiple placeholder="全部城市" style="width: 200px">
            <el-option
              v-for="city in cityOptions"
              :key="city"
              :label="city"
              :value="city"
            />
          </el-select>
        </el-form-item>
        <el-form-item label="院校类型">
          <el-checkbox-group v-model="filters.types">
            <el-checkbox value="985">985</el-checkbox>
            <el-checkbox value="211">211</el-checkbox>
            <el-checkbox value="double-first-class">双一流</el-checkbox>
            <el-checkbox value="public">公办</el-checkbox>
            <el-checkbox value="private">民办</el-checkbox>
          </el-checkbox-group>
        </el-form-item>
        <el-form-item label="最高学费">
          <el-input-number v-model="filters.maxTuition" :min="0" :step="1000" />
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="runRecommend">执行推荐</el-button>
          <el-button @click="resetFilters">重置</el-button>
        </el-form-item>
      </el-form>
    </el-card>

    <!-- 三档汇总 -->
    <div class="risk-summary" v-if="results.length > 0">
      <el-row :gutter="16">
        <el-col :span="8">
          <el-card shadow="hover" class="risk-card rush">
            <template #header>
              <span>冲 ({{ rushCount }} 所)</span>
            </template>
            <div class="risk-desc">位次高于你的，可以尝试</div>
          </el-card>
        </el-col>
        <el-col :span="8">
          <el-card shadow="hover" class="risk-card stable">
            <template #header>
              <span>稳 ({{ stableCount }} 所)</span>
            </template>
            <div class="risk-desc">位次接近的，重点考虑</div>
          </el-card>
        </el-col>
        <el-col :span="8">
          <el-card shadow="hover" class="risk-card safe">
            <template #header>
              <span>保 ({{ safeCount }} 所)</span>
            </template>
            <div class="risk-desc">位次低于你的，保底选择</div>
          </el-card>
        </el-col>
      </el-row>
    </div>

    <!-- 推荐列表 -->
    <el-card v-if="results.length > 0" shadow="never" class="result-card">
      <template #header>
        <div class="result-header">
          <span>推荐结果</span>
          <el-radio-group v-model="viewMode" size="small">
            <el-radio-button value="table">表格</el-radio-button>
            <el-radio-button value="card">卡片</el-radio-button>
          </el-radio-group>
        </div>
      </template>

      <!-- 表格视图 -->
      <el-table
        v-if="viewMode === 'table'"
        :data="results"
        stripe
        border
        style="width: 100%"
        @row-click="selectRow"
      >
        <el-table-column prop="riskLevel" label="风险" width="80" align="center">
          <template #default="{ row }">
            <el-tag :type="riskTagType(row.riskLevel)" effect="dark">
              {{ riskLabel(row.riskLevel) }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column label="院校" min-width="180">
          <template #default="{ row }">
            <div class="college-name">{{ row.college.name }}</div>
            <div class="college-tags">
              <el-tag v-if="row.college.tags.is985" size="small" type="danger">985</el-tag>
              <el-tag v-if="row.college.tags.is211" size="small" type="warning">211</el-tag>
              <el-tag v-if="row.college.tags.isDoubleFirstClass" size="small" type="success">双一流</el-tag>
              <el-tag v-if="!row.college.tags.isPublic" size="small">民办</el-tag>
            </div>
          </template>
        </el-table-column>
        <el-table-column prop="group.groupName" label="专业组" min-width="150" />
        <el-table-column label="城市" width="100">
          <template #default="{ row }">{{ row.college.city }}</template>
        </el-table-column>
        <el-table-column label="最低位次" width="120" align="right">
          <template #default="{ row }">
            {{ row.admission.lowestPosition.toLocaleString() }}
          </template>
        </el-table-column>
        <el-table-column label="位次差" width="100" align="right">
          <template #default="{ row }">
            {{ row.distancePercent > 0 ? '+' : '' }}{{ row.distancePercent.toFixed(1) }}%
          </template>
        </el-table-column>
        <el-table-column label="置信度" width="120" align="center">
          <template #default="{ row }">
            <el-progress
              :percentage="row.confidence"
              :color="getConfidenceColor(row.confidence)"
              :stroke-width="6"
            />
          </template>
        </el-table-column>
        <el-table-column label="就业/升学" width="140">
          <template #default="{ row }">
            <div class="inline-stats">
              <el-tag v-if="row.employment" size="small" type="success">
                就业率 {{ (row.employment as any[]).length > 0 ? getLatestRate(row.employment) : '--' }}%
              </el-tag>
              <el-tag v-if="row.postgraduate" size="small" type="warning">
                升学率 {{ (row.postgraduate as any[]).length > 0 ? getPgRate(row.postgraduate) : '--' }}%
              </el-tag>
              <span v-else class="no-data">--</span>
            </div>
          </template>
        </el-table-column>
        <el-table-column label="操作" width="120" align="center">
          <template #default="{ row }">
            <el-button link type="primary" size="small" @click.stop="addToVolunteer(row)">
              加入志愿表
            </el-button>
          </template>
        </el-table-column>
      </el-table>

      <!-- 卡片视图 -->
      <el-row v-else :gutter="16">
        <el-col :span="8" v-for="item in results" :key="item.group.id">
          <el-card shadow="hover" class="recommend-card">
            <div class="card-risk">
              <el-tag :type="riskTagType(item.riskLevel)" effect="dark" size="large">
                {{ riskLabel(item.riskLevel) }}
              </el-tag>
            </div>
            <h3 class="card-name">{{ item.college.name }}</h3>
            <div class="card-city">{{ item.college.city }}</div>
            <div class="card-tags">
              <el-tag v-if="item.college.tags.is985" size="small" type="danger">985</el-tag>
              <el-tag v-if="item.college.tags.is211" size="small" type="warning">211</el-tag>
              <el-tag v-if="item.college.tags.isDoubleFirstClass" size="small" type="success">双一流</el-tag>
            </div>
            <div class="card-info">
              <div class="info-row">
                <span>专业组</span>
                <span>{{ item.group.groupName }}</span>
              </div>
              <div class="info-row">
                <span>最低位次</span>
                <span>{{ item.admission.lowestPosition.toLocaleString() }}</span>
              </div>
              <div class="info-row">
                <span>位次差</span>
                <span :class="item.distancePercent > 0 ? 'text-danger' : 'text-success'">
                  {{ item.distancePercent > 0 ? '+' : '' }}{{ item.distancePercent.toFixed(1) }}%
                </span>
              </div>
              <div class="info-row" v-if="item.employment">
                <span>就业率</span>
                <span class="text-success">{{ getLatestRate(item.employment as any[]) }}%</span>
              </div>
              <div class="info-row" v-if="item.postgraduate">
                <span>升学率</span>
                <span>{{ getPgRate(item.postgraduate as any[]) }}%</span>
              </div>
            </div>
            <el-button type="primary" size="small" style="width: 100%; margin-top: 12px;" @click="addToVolunteer(item)">
              加入志愿表
            </el-button>
          </el-card>
        </el-col>
      </el-row>
    </el-card>

    <!-- 空状态 -->
    <el-empty v-else :description="'点击执行推荐'" :image-size="200" />
  </div>
</template>

<script setup lang="ts">
import { ref, computed } from 'vue';
import { ElMessage } from 'element-plus';
import { useUserStore } from '@/stores/user';
import type { Recommendation } from '@ga/shared/types';

const user = useUserStore();

const filters = ref({
  cities: [] as string[],
  types: [] as string[],
  maxTuition: undefined as number | undefined,
});

const viewMode = ref<'table' | 'card'>('table');

const results = ref<Recommendation[]>([]);

const cityOptions = [
  '石家庄', '保定', '唐山', '秦皇岛', '邯郸', '邢台', '张家口', '承德', '沧州', '廊坊', '衡水',
  '北京', '天津', '上海', '广州', '深圳', '杭州', '南京', '济南', '青岛', '郑州', '太原', '沈阳', '大连',
];

const rushCount = computed(() => results.value.filter((r) => r.riskLevel === 'rush').length);
const stableCount = computed(() => results.value.filter((r) => r.riskLevel === 'stable').length);
const safeCount = computed(() => results.value.filter((r) => r.riskLevel === 'safe').length);

function riskTagType(level: string): 'danger' | 'warning' | 'success' {
  return level === 'rush' ? 'danger' : level === 'stable' ? 'warning' : 'success';
}

function riskLabel(level: string): string {
  return level === 'rush' ? '冲' : level === 'stable' ? '稳' : '保';
}

function getConfidenceColor(confidence: number): string {
  return confidence >= 80 ? '#67c23a' : confidence >= 50 ? '#e6a23c' : '#f56c6c';
}

function getLatestRate(employment: any[]): number {
  if (!employment || employment.length === 0) return 0;
  const sorted = [...employment].sort((a: any, b: any) => b.data_year - a.data_year);
  return sorted[0]?.employment_rate ?? 0;
}

function getPgRate(postgraduate: any[]): number {
  if (!postgraduate || postgraduate.length === 0) return 0;
  return postgraduate[0]?.advancement_rate ?? 0;
}

function runRecommend() {
  // TODO: 调用实际推荐 API
  // 这里用模拟数据演示
  ElMessage.info('推荐功能开发中，请先完成数据导入');
}

function addToVolunteer(item: Recommendation | any) {
  const name = (item as Recommendation)?.college?.name || '该院校';
  ElMessage.success(`已将 ${name} 加入志愿表`);
}

function selectRow(row: Recommendation) {
  // 查看详情
}

function resetFilters() {
  filters.value = { cities: [], types: [], maxTuition: undefined };
}
</script>

