import { defineStore } from 'pinia';
import type { UserInput, Category, SelectMode } from '@ga/shared/types';

export const useUserStore = defineStore('user', {
  state: () => ({
    // 考生基本信息
    province: '河北省',
    selectMode: '3+1+2' as SelectMode,
    category: 'physical' as Category,
    score: 0,
    position: 0,
    year: new Date().getFullYear() + 1,
  }),

  getters: {
    userInput: (state): UserInput => ({
      province: state.province,
      selectMode: state.selectMode,
      category: state.category,
      score: state.score,
      position: state.position,
      preferences: {},
    }),

    categoryLabel: (state) =>
      state.category === 'physical' ? '物理类' : '历史类',

    hasValidInput: (state) => state.score > 0 && state.position > 0,
  },

  actions: {
    setCategory(cat: Category) {
      this.category = cat;
    },
    setScore(score: number) {
      this.score = score;
    },
    setPosition(pos: number) {
      this.position = pos;
    },
    setProvince(province: string) {
      this.province = province;
    },
  },
});
